blocks.body:
{
    "level": "A2–B1",
    "intro": "W tym temacie nauczysz się <strong>kolejności słów</strong> z czasownikami posiłkowymi, modalnymi i frazowymi: struktura zdania i zasady umieszczania dodatków.",
    "rules": [
        {
            "label": "Środki pomocnicze",
            "color": "emerald",
            "text": "<strong>Temat + Pomocniczy + czasownik główny + dopełnienie: ",
            "example": "Ona czyta książkę. <strong>wymagane</strong> pomiędzy czasownikiem a partykułą:"
        },
        {
            "label": "Модальні",
            "color": "blue",
            "text": "<strong>Subject + Modal + Base Verb + Object</strong> (без to):",
            "example": "He can speak English."
        },
        {
            "label": "Phrasal Verbs",
            "color": "amber",
            "text": "Займенник <strong>обовʼязково</strong> між дієсловом і часткою:",
            "example": "Wyłącz to. (NIE: wyłącz to.)"
        }
    ]
}

{
    "title": "1. Czasowniki pomocnicze",
    "intro": "Czasowniki pomocnicze be, do, have stoją przed czasownikiem głównym:",
    "items": [
        {
            "label": "Be",
            "title": "Ciągły / Pasywny",
            "subtitle": "Ona czyta. / Książka została napisana."
        },
        {
            "label": "Mają",
            "title": "Czasy dokonane",
            "subtitle": "Skończyły się. / Odszedł."
        },
        {
            "label": "Do",
            "title": "Pytania / Negatywy",
            "subtitle": "Czy wiesz? / Ona tego nie lubi."
        }
    ]
}

{
    "title": "2. Czasowniki modalne",
    "sections": [
        {
            "label": "Struktura z modalami",
            "color": "emerald",
            "description": "Czasowniki modalne <strong>can, must, must, must, will, will</strong> stoją przed czasownikiem głównym (bez to).",
            "examples": [
                {
                    "en": "Ona potrafi mówić po angielsku.",
                    "ua": "Potrafi mówić po angielsku Angielski."
                },
                {
                    "en": "Powinieneś dokończyć pracę domową.",
                    "ua": "Powinieneś dokończyć pracę domową."
                },
                {
                    "en": "Musi wezwać lekarza.",
                    "ua": "Musi wezwać lekarza."
                },
                {
                    "en": "Mogą przyjechać późno.",
                    "ua": "Mogą się spóźnić."
                }
            ]
        },
        {
            "label": "Sprzeciw modalne",
            "color": "sky",
            "description": "W przeczeniach <strong>not</strong> jest umieszczane po czasowniku modalnym.",
            "examples": [
                {
                    "en": "Ona nie umie (nie) pływać.",
                    "ua": "Ona nie umie pływać."
                },
                {
                    "en": "Nie powinieneś (nie powinieneś) też jeść dużo.",
                    "ua": "je za dużo."
                },
                {
                    "en": "Nie może (nie może) się spóźniać.",
                    "ua": "Nie może się spóźniać."
                }
            ],
            "note": "Po czasowniku modalnym zawsze występuje forma podstawowa (bez to, bez -s)."
        }
    ]
}

{
    "title": "3. Czasowniki frazowe - rozdzielne (rozdzielne)",
    "sections": [
        {
            "label": "Przyrostek rzeczownika",
            "color": "emerald",
            "description": "Przyrostek rzeczownika może znajdować się <strong>pomiędzy</strong> czasownikiem a partykułą lub <strong>po</strong> całej konstrukcji.",
            "examples": [
                {
                    "en": "Wyłącz światło. = Wyłącz światło.",
                    "ua": "Wyłącz światło."
                },
                {
                    "en": "Odbierz paczkę. = Odbierz paczkę.",
                    "ua": "Weź paczkę."
                },
                {
                    "en": "Załóż płaszcz. = Załóż płaszcz.[[[CODX_SEG_22]. ❌ Wyłącz to.",
                    "ua": "Надягни пальто."
                }
            ]
        },
        {
            "label": "Додаток-займенник",
            "color": "rose",
            "description": "Займенник (it, him, her, them) <strong>ОБОВ'ЯЗКОВО</strong> стоїть між дієсловом і часткою.",
            "examples": [
                {
                    "en": "Turn it off. ❌ Turn off it.",
                    "ua": "Wyłącz to."
                },
                {
                    "en": "Podnieś je. ❌ Podnieś je.",
                    "ua": "Podnieś."
                },
                {
                    "en": "Załóż to. ❌ Załóż to.",
                    "ua": "Załóż to."
                }
            ],
            "note": "Ta zasada jest obowiązkowa! Zaimek nigdy nie następuje po cząstce."
        }
    ]
}

{
    "title": "4. Czasowniki frazowe - nierozłączne (nierozłączne)",
    "sections": [
        {
            "label": "Dodatek po czasowniku frazowym",
            "color": "emerald",
            "description": "W przypadku <strong>nierozłącznych</strong> czasowników frazowych aplikacja jest zawsze <strong>po</strong> całej konstrukcji.",
            "examples": [
                {
                    "en": "Dbaj o swoje psa.",
                    "ua": "Zaopiekuj się swoim psem."
                },
                {
                    "en": "Pokonała chorobę.",
                    "ua": "Poradziła sobie z chorobą."
                },
                {
                    "en": "Natrafiłam na stare zdjęcie.",
                    "ua": "Natrafiłam na stare zdjęcie zdjęcie."
                },
                {
                    "en": "Wpadł na starego przyjaciela.",
                    "ua": "W drugiej kolejności spotkał starego przyjaciela."
                }
            ]
        },
        {
            "label": "Czasowniki frazowe składające się z trzech słów",
            "color": "sky",
            "description": "Czasowniki frazowe zawierające trzywyrazy są <strong>zawsze</strong> nierozłączne.",
            "examples": [
                {
                    "en": "Nie może znieść hałasu.",
                    "ua": "Nie może znieść hałasu."
                },
                {
                    "en": "Nie mogę się doczekać wyjazdu.",
                    "ua": "Nie mogę się doczekać wyjazdu podróż."
                },
                {
                    "en": "Skończyło się mleko.",
                    "ua": "Skończyło się mleko."
                }
            ]
        }
    ]
}

{
    "title": "5. Popularne czasowniki frazowe",
    "intro": "Pamiętaj, które czasowniki frazowe można rozdzielić, a które nie:",
    "rows": [
        {
            "en": "włącz/wyłącz",
            "ua": "włącz/wyłącz",
            "note": "Podziel"
        },
        {
            "en": "wybierz w górę",
            "ua": "podnieś, odbierz",
            "note": "rozproszone"
        },
        {
            "en": "włóż",
            "ua": "włóż",
            "note": "rozproszone"
        },
        {
            "en": "wrzuć daleko",
            "ua": "",
            "note": "Przydzielone"
        },
        {
            "en": "opiekuj się",
            "ua": "opiekuj",
            "note": "nieprzydzielone"
        },
        {
            "en": "szukaj",
            "ua": "szukaj for[[[CODX_6]]]Nieprzydzielone",
            "note": "Нерозділюване"
        },
        {
            "en": "przeboleć",
            "ua": "odzyskać, pokonać",
            "note": "nierozłączne"
        }
    ],
    "warning": "📌 Jeśli nie jesteś pewien - sprawdź w słowniku!"
}

{
    "title": "6. Typowe błędy osób mówiących po ukraińsku",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Zaimek po imiesłowu zamiast pomiędzy.",
            "wrong": "Wyłącz to.",
            "right": " ✅ <span class="font-mono">Włącz to wyłączony.</span>"
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Czasownik modalny + do.",
            "wrong": "Umie pływać.",
            "right": "​​​​​​​​ czasownik."
        },
        {
            "label": "Помилка 3",
            "color": "sky",
            "title": "Розділення нерозділюваного phrasal verb.",
            "wrong": "Przyjrzyj się swojemu psu po.",
            "right": "​​​​ <span class="font-mono">Zaopiekuj się swoim psem.</span>"
        },
        {
            "label": "Błąd 4",
            "color": "purple",
            "title": "Czasownik z -s po modalnym.",
            "wrong": "Musi dzwoni.",
            "right": "​​​​ <span class="font-mono">Musi zadzwonić.</span>"
        }
    ]
}

{
    "title": "7. Krótkie streszczenie",
    "items": [
        "Środki pomocnicze (be, do, have): <strong>S + Aux + V + O</strong>.",
        "]Modały: <strong>S + modalne + czasownik podstawowy + O</strong> (bez to, bez -s).",
        "Czasowniki frazowe rozłączne: załącznik może być pomiędzy lub po.",
        "Zaimek w rozłącznym: <strong>wymagany</strong> pomiędzy czasownikiem a partykułą.",
        "Czasowniki frazowe nierozłączne i składające się z 3 wyrazów: dodatek <strong>po</strong> całej konstrukcji."
    ]
}

{
    "title": "8. Ćwicz",
    "select_title": "Ćwiczenie 1. Wybierz właściwą opcję",
    "select_intro": "Wybierz zdania z odpowiednią kolejnością słów.",
    "selects": [
        {
            "label": "a) Wyłącz to. / b) Wyłącz to.",
            "prompt": "Która opcja jest poprawna?"
        },
        {
            "label": "a) Potrafi pływać. / b) Umie pływać.",
            "prompt": "Która opcja jest poprawna?"
        },
        {
            "label": "a) Zaopiekuj się dziećmi. / b) Opiekuj się dziećmi.",
            "prompt": "Która opcja jest poprawna?"
        }
    ],
    "options": [
        "a",
        "b"
    ],
    "input_title": "Ćwiczenie 2. Wstaw zaimek we właściwe miejsce",
    "input_intro": "Zastąp rzeczownik zaimkiem w nawiasy.",
    "inputs": [
        {
            "before": " Podnieś książkę. (it)",
            "after": " →"
        },
        {
            "before": "Wyłącz telewizor. (it)",
            "after": " →"
        },
        {
            "before": "Załóż buty. (im)",
            "after": "→"
        }
    ],
    "rephrase_title": "Ćwiczenie 3. Popraw błąd",
    "rephrase_intro": "Znajdź i popraw błąd w kolejności wyrazów.",
    "rephrase": [
        {
            "example_label": "Przykład:",
            "example_original": "Musi zadzwonić niego.",
            "example_target": "Musi do niego zadzwonić."
        },
        {
            "original": "1. Umie grać na gitarze.",
            "placeholder": "Popraw kolejność słów"
        },
        {
            "original": "2. Rzuć je. okoliczności",
            "placeholder": "Виправ порядок слів"
        }
    ]
}

{
    "title": "Інші сторінки з базової граматики",
    "items": [
        {
            "label": "Basic Word Order — Порядок слів у ствердженні",
            "current": false
        },
        {
            "label": "Word Order in Questions and Negatives — Питання та заперечення",
            "current": false
        },
        {
            "label": "Word Order with Adverbs — Прислівники та обставини",
            "current": false
        },
        {
            "label": "Kolejność wyrazów z czasownikami i dopełnieniami – czasowniki i afiksy (bieżące)",
            "current": true
        },
        {
            "label": "Zaawansowany szyk wyrazów – inwersja i wzmocnienie",
            "current": false
        }
    ]
}
